svg.script:
(function() {
  const polygon = document.getElementById("spinner");
  let currentPoints = [];
  let animationsPaused = false;
  let voteCount = 0;

  // Variables de zoom
  let zoomLevel = 1;
  const minZoom = 0.3;
  const maxZoom = 3.0;
  const zoomStep = 0.2;

  // Generar puntos dinámicos EXACTAMENTE como V2
  function generateStarPoints(spike = 60) {
    const base = 150; // Como V2 original
    const newPoints = [];
    for (let i = 0; i < 8; i++) {
      const angle = (Math.PI * 2 * i) / 8;
      const variation = base + (Math.random() - 0.5) * spike;
      const x = Math.cos(angle) * variation;
      const y = Math.sin(angle) * variation;
      newPoints.push({ x, y });
    }
    return newPoints;
  }

  function interpolatePoints(p1, p2, t) {
    return p1.map((pt, i) => ({
      x: pt.x + (p2[i].x - pt.x) * t,
      y: pt.y + (p2[i].y - pt.y) * t
    }));
  }

  function pointsToString(pts) {
    return pts.map(p => `${p.x.toFixed(2)},${p.y.toFixed(2)}`).join(" ");
  }

  let targetPoints = generateStarPoints();
  currentPoints = targetPoints.map(p => ({ ...p }));
  let tick = 0;

  function animate() {
    if (!animationsPaused && polygon) {
      tick++;
      if (tick % 180 === 0) {
        targetPoints = generateStarPoints(60);
      }

      currentPoints = interpolatePoints(currentPoints, targetPoints, 0.03);
      polygon.setAttribute("points", pointsToString(currentPoints));
    }
    requestAnimationFrame(animate);
  }

  // Sistema de zoom
  const svgElement = document.getElementById('parlamento-bio-token-v4');
  const zoomGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g');
  zoomGroup.id = 'zoom-group';
  zoomGroup.setAttribute('transform', 'translate(0,0) scale(1)');

  // Mover solo el gráfico principal al zoom
  const mainGraph = document.querySelector('g[transform="translate(400,400)"]');
  const zoomIndicator = document.getElementById('zoom-indicator');

  if (mainGraph) {
    zoomGroup.appendChild(mainGraph);
    svgElement.insertBefore(zoomGroup, document.getElementById('zoom-controls'));
  }

  function updateZoom() {
    zoomGroup.setAttribute('transform', `scale(${zoomLevel})`);
    if (zoomIndicator) {
      zoomIndicator.textContent = Math.round(zoomLevel * 100) + '%';
    }
  }

  // Funciones globales para zoom
  window.zoomInFunction = function() {
    if (zoomLevel < maxZoom) {
      zoomLevel = Math.min(zoomLevel + zoomStep, maxZoom);
      updateZoom();
    }
  };

  window.zoomOutFunction = function() {
    if (zoomLevel > minZoom) {
      zoomLevel = Math.max(zoomLevel - zoomStep, minZoom);
      updateZoom();
    }
  };

  // Interactividad de puntos parlamentarios EXACTAMENTE como V2
  const parliamentDots = document.querySelectorAll('.parliament-dot');
  let participation = 75;
  let voteCount = 0;

  parliamentDots.forEach(dot => {
    dot.addEventListener('click', function() {
      participation = Math.min(100, participation + 1);
      voteCount++;

      // Efecto visual en el punto
      const originalOpacity = this.getAttribute('opacity');
      const originalRadius = this.getAttribute('r');

      this.setAttribute('opacity', '1');
      this.setAttribute('r', parseFloat(originalRadius) * 2);
      this.setAttribute('stroke', '#fff');
      this.setAttribute('stroke-width', '2');
      this.style.filter = 'url(#glow1)';

      setTimeout(() => {
        this.setAttribute('opacity', originalOpacity);
        this.setAttribute('r', originalRadius);
        this.removeAttribute('stroke');
        this.removeAttribute('stroke-width');
        this.style.filter = '';
      }, 2000);

      const species = this.getAttribute('data-species');
      console.log(`🗳️ Voto ${voteCount}: ${species} - Participación: ${participation}%`);
    });
  });

  // Control de teclado
  document.addEventListener('keydown', function(e) {
    if (e.code === 'Space') {
      e.preventDefault();
      animationsPaused = !animationsPaused;

      const allAnimated = document.querySelectorAll('.parliament-seats, .parliament-dot, .parliament-dots');
      allAnimated.forEach(el => {
        el.style.animationPlayState = animationsPaused ? 'paused' : 'running';
      });

      console.log(animationsPaused ? '⏸️ Parlamento pausado' : '▶️ Parlamento activo');
    }
  });

  // Iniciar
  animate();
  console.log('🏛️ Parlamento de Todas las Cosas V4.0 cargado');
  console.log('🗳️ Click en puntos parlamentarios para votar - ESPACIO pausa/reanuda');
  console.log('🎛️ Total escaños: ' + parliamentDots.length + ' | 7 niveles concéntricos | 8 especies');
  console.log('🔍 ZOOM: Solo botones +/- para zoom');
  console.log('🧬 eDNA: 8 sitios de validación regional');
  console.log('🍄 Fungi: 8 nodos de red micorrízica');
  console.log('🤖 Agencia IA: Meta-gobernanza activa');
})();
